import { useState, useCallback } from 'react';
import { apiPost } from '../utils/api';

/**
 * Hook to initiate Stripe checkout for tier upgrade.
 * Returns { checkout, loading, error }
 */
export default function useStripeCheckout() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const checkout = useCallback(async (tier, billingPeriod = 'monthly') => {
    setLoading(true);
    setError(null);
    try {
      const data = await apiPost('/billing/platform/checkout', {
        tier,
        billing_period: billingPeriod,
      });
      if (data?.checkout_url) {
        window.location.href = data.checkout_url;
      } else if (data?.url) {
        window.location.href = data.url;
      } else {
        setError(data?.detail || data?.error || 'Failed to create checkout session');
      }
    } catch (e) {
      setError(e.message || 'Checkout failed');
    } finally {
      setLoading(false);
    }
  }, []);

  return { checkout, loading, error };
}
